import{_ as a,o as t,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"8. Apprentices","description":"","frontmatter":{"title":"8. Apprentices","eba":"Health Allied & Managers Admin 2021-2025","topics":["wages","training"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/wages/8-apprentices.md","filePath":"ebas/has-managers-admin/health-allied-services/wages/8-apprentices.md"}'),n={name:"ebas/has-managers-admin/health-allied-services/wages/8-apprentices.md"};function i(p,e,o,c,l,h){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_8-apprentices" tabindex="-1">8. Apprentices <a class="header-anchor" href="#_8-apprentices" aria-label="Permalink to &quot;8. Apprentices&quot;">​</a></h1><p><strong>8.1</strong> Apprentice Cooks Apprentice Cooks will be paid the rate set out in Part 1 of <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedule 2B</a>.</p><p><strong>8.2</strong> Adult Apprentices</p><p><strong>(a)</strong> An adult apprentice is an apprentice who is 21 years of age or over at the commencement of their apprenticeship.</p><p><strong>(b)</strong> The minimum rate for an adult apprentice will be the rate prescribed for apprentices in this clause 8 or the rate provided in the Modern Award, whichever is greater.</p><p><strong>(c)</strong> Where an adult apprentice was an Employee of the Employer for a period of at least six months immediately prior to becoming an apprentice, they will not suffer a reduction in their base rate of pay on entering into the training agreement.</p><p>PART E – ALLOWANCES AND REIMBURSEMENTS</p>',7)])])}const g=a(n,[["render",i]]);export{m as __pageData,g as default};
